function solve(nums) {
    const n = nums.length;
    if (n === 0) return 0;

    const maxNum = 1000000;
    const spf = new Array(maxNum + 1).fill(0);

    for (let i = 2; i <= maxNum; i++) {
        if (spf[i] === 0) {
            spf[i] = i;
            for (let j = i * 2; j <= maxNum; j += i) {
                if (spf[j] === 0) {
                    spf[j] = i;
                }
            }
        }
    }

    function getPrimes(x) {
        const primes = new Set();
        if (x === 1) return primes;
        let current = x;
        while (current !== 1) {
            const p = spf[current];
            primes.add(p);
            while (current % p === 0) {
                current /= p;
            }
        }
        return primes;
    }

    const primeIndices = new Map();
    for (let i = 0; i < n; i++) {
        const x = nums[i];
        const primes = getPrimes(x);
        for (const p of primes) {
