        }
    }

    const visited = new Array(n).fill(false);
    const queue = [[0, 0]];
    visited[0] = true;

    while (queue.length > 0) {
        const [current, steps] = queue.shift();
        if (current === n - 1) {
            return steps;
        }

        const nextIndices = [];

        if (current - 1 >= 0 && !visited[current - 1]) {
            nextIndices.push(current - 1);
        }
        if (current + 1 < n && !visited[current + 1]) {
            nextIndices.push(current + 1);
        }

        const currentPrimes = getPrimes(nums[current]);
        if (currentPrimes.size === 1 && currentPrimes.has(nums[current])) {
