        const primes = new Set();
        if (x === 1) return primes;
        while (x !== 1) {
            const p = spf[x];
            primes.add(p);
            while (x % p === 0) {
                x /= p;
            }
        }
        return primes;
    }

    const primeIndices = new Map();
    for (let i = 0; i < n; i++) {
